static inline uint32_t CeilDiv(uint64_t a, uint32_t b)
{
    return static_cast<uint32_t>((a + b - 1ULL) / static_cast<uint64_t>(b));
}
}

namespace optiling {

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvTransposed3dAsymmetricInputSquareKernelCustomTilingData tiling;

    // Input shapes
    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    // Expect x: [N, Cin, Din, Hin, Win], w: [Cin, Cout, Kd, Kh, Kw] (PyTorch conv_transpose3d layout)
    if (x_shape->GetOriginShape().GetDimNum() != 5 || w_shape->GetOriginShape().GetDimNum() != 5) {
        return ge::GRAPH_FAILED;
    }

    const auto &x_dims = x_shape->GetOriginShape().GetDims();
    const auto &w_dims = w_shape->GetOriginShape().GetDims();

    const uint32_t N   = static_cast<uint32_t>(x_dims[0]);
    const uint32_t Cin = static_cast<uint32_t>(x_dims[1]);
    const uint32_t Din = static_cast<uint32_t>(x_dims[2]);
    const uint32_t Hin = static_cast<uint32_t>(x_dims[3]);
    const uint32_t Win = static_cast<uint32_t>(x_dims[4]);

    const uint32_t W_Cin  = static_cast<uint32_t>(w_dims[0]);
    const uint32_t W_Cout = static_cast<uint32_t>(w_dims[1]);
    const uint32_t Kd = static_cast<uint32_t>(w_dims[2]);
    const uint32_t Kh = static_cast<uint32_t>(w_dims[3]);
    const uint32_t Kw = static_cast<uint32_t>(w_dims[4]);

    if (W_Cin != Cin) {
        return ge::GRAPH_FAILED;
    }

    // Fixed attributes for this optimized kernel:
    // stride=(1,1,1), padding=(0,0,0), dilation=(1,1,1), output_padding=(0,0,0), groups=1
    const uint32_t Dout = Din + Kd - 1;
    const uint32_t Hout = Hin + Kh - 1;
    const uint32_t Wout = Win + Kw - 1;
    const uint32_t Cout = W_Cout;

    // Set blockDim based on total output elements
    const uint64_t totalY = static_cast<uint64_t>(N) * Cout * Dout * Hout * Wout;
    uint32_t blockDim = 24u;
    uint32_t maxBlocks = 32u;
    uint32_t suggested = CeilDiv(totalY, 1024u);
    if (suggested < 1u) suggested = 1u;
    if (suggested > maxBlocks) suggested = maxBlocks;
    blockDim = suggested;

    context->SetBlockDim(blockDim);

    tiling.set_n(N);
    tiling.set_cin(Cin);
    tiling.set_cout(Cout);
    tiling.set_din(Din);
    tiling.set_hin(Hin);
    tiling.set_win(Win);
    tiling.set_kd(Kd);
    tiling.set_kh(Kh);
    tiling.set_kw(Kw);
    tiling.set_dout(Dout);
    tiling.set_hout(Hout);
    tiling.set_wout(Wout);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;

    return ge::GRAPH_SUCCESS;
}

