at::Tensor conv_transposed_3d_asymmetric_input_square_kernel_custom_impl_npu(const at::Tensor& x, const at::Tensor& weight) {
    // Output shape: N, Cout, Din+Kd-1, Hin+Kh-1, Win+Kw-1
    TORCH_CHECK(x.dim() == 5 && weight.dim() == 5, \"Expected 5D tensors\");
    TORCH_CHECK(x.scalar_type() == at::kFloat && weight.scalar_type() == at::kFloat, \"Expected float tensors\");

    auto N = x.size(0);
    auto Cin = x.size(1);
    auto Din = x.size(2);
    auto Hin = x.size(3);
    auto Win = x.size(4);

    auto W_Cin = weight.size(0);
    auto Cout = weight.size(1);
    auto Kd = weight.size(2);
    auto Kh = weight.size(3);
    auto Kw = weight.size(4);

    TORCH_CHECK(W_Cin == Cin, \"Weight Cin must match input Cin\");
    auto Dout = Din + Kd - 1;
    auto Hout = Hin + Kh - 1;
    auto Wout = Win + Kw - 1;

    at::Tensor y = at::empty({N, Cout, Dout, Hout, Wout}, x.options());
    EXEC_NPU_CMD(aclnnConvTransposed3dAsymmetricInputSquareKernelCustom, x, weight, y);
    return y;
}

